func solve(prices []int64, strategy []int64, k int64) int64 {
    n := len(prices)
    original_profit := int64(0)
    prefix_original := make([]int64, n+1)
    prefix_diff := make([]int64, n+1)

    for i := 0; i < n; i++ {
        original_profit += strategy[i] * prices[i]
        prefix_original[i+1] = prefix_original[i] + strategy[i] * prices[i]
        prefix_diff[i+1] = prefix_diff[i] + (1 - strategy[i]) * prices[i]
    }

    max_gain := int64(0)
    half_k := k / 2

    for i := 0; i <= n - k; i++ {
        sum_first := prefix_original[i + half_k] - prefix_original[i]
        sum_second := prefix_diff[i + k] - prefix_diff[i + half_k]
        gain := sum_second - sum_first
        if gain > max_gain {
            max_gain = gain
        }
    }

    return original_profit + max_gain
}
